from typing import Any, Dict, List, Optional

import requests


DEFAULT_ADMIN_URL = os.getenv("KONG_ADMIN_URL", "http://localhost:8001")
DEFAULT_TIMEOUT = int(os.getenv("KONG_ADMIN_TIMEOUT", "10"))


class KongAdminClient:
    def __init__(self, admin_url: str, timeout: int = 10, headers: Optional[Dict[str, str]] = None) -> None:
        self.admin_url = admin_url.rstrip("/")
        self.timeout = timeout
        self.session = requests.Session()
        self.session.headers.update(headers or {"Content-Type": "application/json"})

    def _url(self, path: str) -> str:
        return f"{self.admin_url}/{path.lstrip('/')}"

    def _request(self, method: str, path: str, payload: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
        url = self._url(path)
        response = self.session.request(
            method=method.upper(),
            url=url,
            json=payload,
            timeout=self.timeout,
        )
        if not response.ok:
            raise RuntimeError(
                f"Kong Admin API request failed: {method.upper()} {url} "
                f"status={response.status_code} body={response.text}"
            )
        if response.text.strip():
            return response.json()
        return {}

    def get(self, path: str) -> Dict[str, Any]:
        return self._request("GET", path)

    def post(self, path: str, payload: Dict[str, Any]) -> Dict[str, Any]:
        return self._request("POST", path, payload)

    def put(self, path: str, payload: Dict[str, Any]) -> Dict[str, Any]:
        return self._request("PUT", path, payload)


def ensure_service(client: KongAdminClient, service: Dict[str, Any]) -> Dict[str, Any]:
    name = service["name"]
    return client.put(f"/services/{name}", service)


def ensure_route(client: KongAdminClient, service_name: str, route: Dict[str, Any]) -> Dict[str, Any]:
    route_name = route["name"]
    return client.put(f"/services/{service_name}/routes/{route_name}", route)


def ensure_upstream(client: KongAdminClient, upstream: Dict[str, Any]) -> Dict[str, Any]:
    name = upstream["name"]
    payload = {k: v for k, v in upstream.items() if k != "targets"}
    return client.put(f"/upstreams/{name}", payload)


def ensure_target(client: KongAdminClient, upstream_name: str, target: Dict[str, Any]) -> Dict[str, Any]:
    return client.post(f"/upstreams/{upstream_name}/targets", target)


def configure_kong(client: KongAdminClient, config: Dict[str, Any]) -> Dict[str, Any]:
    results: Dict[str, Any] = {
        "services": [],
        "routes": [],
        "upstreams": [],
        "targets": [],
    }

    for upstream in config.get("upstreams", []):
        upstream_result = ensure_upstream(client, upstream)
        results["upstreams"].append(upstream_result)

        for target in upstream.get("targets", []):
            target_result = ensure_target(client, upstream["name"], target)
            results["targets"].append(target_result)
            time.sleep(0.05)

    for service in config.get("services", []):
        service_result = ensure_service(client, service)
        results["services"].append(service_result)

        for route in service.get("routes", []):
            route_payload = dict(route)
            route_result = ensure_route(client, service["name"], route_payload)
            results["routes"].append(route_result)

    return results


